// In production: replace this node with a Google Sheets 'Read All Rows' node
// pointing to the 'Prudentia Demo - SME Client Register' sheet.

const today = new Date();

const demoClients = [
  {
    client_name: 'Nomvula Dlamini Attorneys Inc.',
    email: 'demo+nomvula@prudentiadigital.co.za',
    service: 'Monthly Retainer',
    intake_date: new Date(today - 5 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    docs_received: false,
    last_reminder: ''
  },
  {
    client_name: 'Sipho & Partners Accounting',
    email: 'demo+sipho@prudentiadigital.co.za',
    service: 'Bookkeeping Automation',
    intake_date: new Date(today - 8 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    docs_received: false,
    last_reminder: new Date(today - 3 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]
  },
  {
    client_name: 'Lungelo HR Consultancy',
    email: 'demo+lungelo@prudentiadigital.co.za',
    service: 'Employee Onboarding Automation',
    intake_date: new Date(today - 2 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    docs_received: true,
    last_reminder: ''
  }
];

return demoClients.map(c => ({ json: c }));

const today = new Date();

const toChase = $input.all().filter(item => {
  const client = item.json;
  if (client.docs_received === true || client.docs_received === 'TRUE') return false;

  const intakeDate = new Date(client.intake_date);
  const daysSinceIntake = Math.floor((today - intakeDate) / (24 * 60 * 60 * 1000));
  if (daysSinceIntake < 3) return false;

  // Avoid double-chasing same day
  if (client.last_reminder) {
    const lastReminder = new Date(client.last_reminder);
    const daysSinceReminder = Math.floor((today - lastReminder) / (24 * 60 * 60 * 1000));
    if (daysSinceReminder < 1) return false;
  }

  return true;
});

if (toChase.length === 0) {
  return [{ json: { skipped: true, message: 'No clients require chasing today.' } }];
}

return toChase.map(item => ({
  json: {
    ...item.json,
    reminder_date: today.toISOString().split('T')[0]
  }
}));

// In production: update the Google Sheets 'last_reminder' column for this client.
